def compute_score() -> tuple[str, float]:
    # Use screenshots for visual diff since text/shape-level diffs are not fully reliable
    base_img = next((s.image_path for s in original_ppt_screenshots if s.slide_number == 2), None)
    mod_img = next((s.image_path for s in modified_ppt_screenshots if s.slide_number == 2), None)
    if not base_img or not mod_img:
        return ("Missing slide screenshots.", 0.0)
    prompt = (
        "Compare these two images of the same PowerPoint slide. Ignore any difference bullet types/styles (e.g. whether the bullet styles are circle bullets, square bullets, numbers, etc.). "
        "Are there *any* other visible changes to the slide's content, layout, or appearance (such as text, images, shapes, or formatting)? "
        "If there are no other visible changes except bullet style, answer YES. Otherwise, answer NO and briefly describe the differences."
    )
    vlm_resp = vlm_call(prompt, [base_img, mod_img], temperature=0.0, max_tokens=128).strip().lower()
    if vlm_resp.startswith('yes'):
        return ("No extraneous visual changes to Slide 2 besides bullet style.", 1.0)
    else:
        return (f"Visual difference(s) detected on Slide 2 besides bullet style: {vlm_resp}", 0.0)

def compute_score() -> tuple[str, float]:
    from PIL import Image, ImageChops
    import numpy as np
    ok_count = 0
    total = 0
    for orig, mod in zip(original_ppt_screenshots, modified_ppt_screenshots):
        if orig.slide_number == 2:
            continue
        total += 1
        img1 = Image.open(orig.image_path).convert('RGB')
        img2 = Image.open(mod.image_path).convert('RGB')
        diff = ImageChops.difference(img1, img2)
        arr = np.array(diff)
        changed_pixels = np.sum(np.any(arr > 40, axis=-1))
        total_pixels = arr.shape[0]*arr.shape[1]
        pct_change = changed_pixels / total_pixels
        if pct_change <= 0.01:
            ok_count += 1
    if total == 0:
        return ("No other slides to check.", 1.0)
    score = ok_count / total
    if score < 1.0:
        return (f"Some other slides were modified.", score)
    return ("No extraneous changes to other slides.", 1.0)
